TrekKlingonLauncher.prototype.calculateSpecialRangePenalty = function (distance) {
    var distancePenalized = Math.max(0, distance - 10); //ignore first 10 hexes
    var rangePenalty = this.rangePenalty * distancePenalized;
    return rangePenalty;
};

